const AlertManagement = () => {
  const loadRules = useCallback(() => {
    console.log('Loading rules...');
  }, []); // 确保 loadRules 是稳定的

  useEffect(() => {
    loadRules();
  }, [loadRules]); // 修复：将 loadRules 添加到依赖数组

  return <div>Alert Management</div>;
};

export default AlertManagement;
```

